svg.script:
(function() {
  var svg         = document.getElementById('root');
  var dataLayerEl = document.getElementById('data-layer');

  /* §2 isDark hoisted before all build code */
  var isDark = false;

  /* DATA */
  var months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct'];
  var series = [
    { name:'Engineering', cls:'1', values:[95, 95, 110, 110, 128, 128, 155, 155, 182, 182] },
    { name:'Data & ML',   cls:'2', values:[60, 72, 72,  88,  88,  105, 105, 120, 143, 143] },
    { name:'Product',     cls:'3', values:[38, 38, 45,  45,  52,  52,  60,  60,  67,  67 ] },
    { name:'Marketing',   cls:'4', values:[28, 28, 32,  32,  38,  38,  40,  44,  44,  44 ] }
  ];

  /* LAYOUT */
  var plotL = 68, plotR = 850, plotT = 100, plotB = 500;
  var n     = months.length;
  var step  = (plotR - plotL) / (n - 1);
  var yMin  = 0, yMax = 200;

  function xAt(i) { return plotL + i * step; }
  function yAt(v) { return plotB - (v - yMin) / (yMax - yMin) * (plotB - plotT); }

  /* step-after area path: top edge H then V, closed down to baseline */
  function areaPath(values) {
    /* top edge: step-after (H then V) */
    var d = 'M' + xAt(0) + ',' + yAt(values[0]);
    for (var i = 1; i < values.length; i++) {
      d += ' H' + xAt(i) + ' V' + yAt(values[i]);
    }
    /* close: down to baseline, back left, up to start */
    d += ' V' + plotB + ' H' + xAt(0) + ' Z';
    return d;
  }

  /* top stroke only (no close) — drawn on top of fill for crisp edge */
  function strokePath(values) {
    var d = 'M' + xAt(0) + ',' + yAt(values[0]);
    for (var i = 1; i < values.length; i++) {
      d += ' H' + xAt(i) + ' V' + yAt(values[i]);
    }
    return d;
  }

  /* §3 STAGGER — 4 series; dots per series */
  var seriesStagger = 0.20;
  var dotStagger    = Math.min(0.25, 1.0 / n);
  var lastDelay     = (series.length - 1) * seriesStagger + (n - 1) * dotStagger;
  var readyDelay    = (lastDelay + 0.8 + 0.1) * 1000;

  /* BUILD DOM
     Paint back-to-front so foreground series sit on top.
     Series 0 has the highest values and is painted last (on top). */
  var sgEls = [];

  for (var si = series.length - 1; si >= 0; si--) {
    (function(si) {
      var s  = series[si];
      var sg = document.createElementNS('http://www.w3.org/2000/svg', 'g');
      sg.setAttribute('class', 'sg');
      sg.setAttribute('id', 'sg' + si);

      /* area fill */
      var fill = document.createElementNS('http://www.w3.org/2000/svg', 'path');
      fill.setAttribute('class', 'area-fill series-' + s.cls);
      fill.setAttribute('d', areaPath(s.values));
      fill.setAttribute('fill-opacity', '0.18');
      fill.setAttribute('stroke', 'none');
      fill.style.animationDelay = (si * seriesStagger) + 's';
      sg.appendChild(fill);

      /* top stroke */
      var stroke = document.createElementNS('http://www.w3.org/2000/svg', 'path');
      stroke.setAttribute('class', 'area-stroke series-' + s.cls);
      stroke.setAttribute('d', strokePath(s.values));
      stroke.style.fill = 'none';
      stroke.setAttribute('stroke-width', '2.5');
      stroke.setAttribute('stroke-linejoin', 'round');
      stroke.style.animationDelay = (si * seriesStagger) + 's';
      sg.appendChild(stroke);

      /* dots at each step */
      s.values.forEach(function(v, i) {
        var dg = document.createElementNS('http://www.w3.org/2000/svg', 'g');
        dg.setAttribute('class', 'dot-g');
        dg.style.animationDelay = (si * seriesStagger + i * dotStagger) + 's';

        var dot = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
        dot.setAttribute('cx', xAt(i)); dot.setAttribute('cy', yAt(v)); dot.setAttribute('r', '4');
        dot.setAttribute('class', 'dot-circle series-' + s.cls);

        var ring = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
        ring.setAttribute('cx', xAt(i)); ring.setAttribute('cy', yAt(v)); ring.setAttribute('r', '4');
        ring.style.fill = 'none';
        ring.setAttribute('class', 'series-' + s.cls);
        ring.setAttribute('stroke-width', '2');

        dg.appendChild(dot);
        dg.appendChild(ring);
        sg.appendChild(dg);
      });

      dataLayerEl.appendChild(sg);
      sgEls.unshift(sg); /* restore original order for hover index lookup */

      /* A1: double rAF then add .visible */
      requestAnimationFrame(function() {
        requestAnimationFrame(function() {
          fill.classList.add('visible');
          stroke.classList.add('visible');
          Array.prototype.forEach.call(sg.querySelectorAll('.dot-g'), function(dg) {
            dg.classList.add('visible');
          });
        });
      });
    })(si);
  }

  /* A1 ready gate */
  setTimeout(function() {
    dataLayerEl.classList.add('ready');
    Array.prototype.forEach.call(dataLayerEl.querySelectorAll('.area-fill'),   function(el) { el.style.opacity = ''; });
    Array.prototype.forEach.call(dataLayerEl.querySelectorAll('.area-stroke'), function(el) { el.style.opacity = ''; });
    Array.prototype.forEach.call(dataLayerEl.querySelectorAll('.dot-g'),       function(el) { el.style.opacity = ''; });
  }, readyDelay);

  /* TOOLTIP */
  var tipBg  = document.getElementById('tip-bg');
  var tipBdr = document.getElementById('tip-bdr');
  var tipTip = document.getElementById('tip-tip');
  var tipVal = document.getElementById('tip-val');
  var tipLbl = document.getElementById('tip-lbl');

  function showTip(cx, cy, valTxt, lblTxt) {
    tipVal.textContent = valTxt;
    tipLbl.textContent = lblTxt;
    var pad = 20, bh = 38, rx = 9, tw = 8, tail = 10;
    var hw  = Math.max(tipVal.getBBox().width, tipLbl.getBBox().width) / 2 + pad / 2;
    var tx  = Math.max(hw + 8, Math.min(cx, plotR - hw - 8));
    var above = (cy - tail - bh - 4) >= plotT;
    var bT, bB;
    if (above) { bB = cy - tail; bT = bB - bh; }
    else        { bT = cy + tail; bB = bT + bh; }

    tipBg.setAttribute('x', tx - hw); tipBg.setAttribute('y', bT);
    tipBg.setAttribute('width', hw * 2); tipBg.setAttribute('height', bh);

    if (above) {
      tipBdr.setAttribute('d',
        'M'+(tx+tw)+','+bB+' L'+(tx+hw-rx)+','+bB+' Q'+(tx+hw)+','+bB+' '+(tx+hw)+','+(bB-rx)+
        ' L'+(tx+hw)+','+(bT+rx)+' Q'+(tx+hw)+','+bT+' '+(tx+hw-rx)+','+bT+
        ' L'+(tx-hw+rx)+','+bT+' Q'+(tx-hw)+','+bT+' '+(tx-hw)+','+(bT+rx)+
        ' L'+(tx-hw)+','+(bB-rx)+' Q'+(tx-hw)+','+bB+' '+(tx-hw+rx)+','+bB+' L'+(tx-tw)+','+bB);
      tipTip.setAttribute('d', 'M'+(tx-tw)+','+bB+' L'+tx+','+(cy-2)+' L'+(tx+tw)+','+bB);
    } else {
      tipBdr.setAttribute('d',
        'M'+(tx-tw)+','+bT+' L'+(tx-hw+rx)+','+bT+' Q'+(tx-hw)+','+bT+' '+(tx-hw)+','+(bT+rx)+
        ' L'+(tx-hw)+','+(bB-rx)+' Q'+(tx-hw)+','+bB+' '+(tx-hw+rx)+','+bB+
        ' L'+(tx+hw-rx)+','+bB+' Q'+(tx+hw)+','+bB+' '+(tx+hw)+','+(bB-rx)+
        ' L'+(tx+hw)+','+(bT+rx)+' Q'+(tx+hw)+','+bT+' '+(tx+hw-rx)+','+bT+' L'+(tx+tw)+','+bT);
      tipTip.setAttribute('d', 'M'+(tx+tw)+','+bT+' L'+tx+','+(cy+2)+' L'+(tx-tw)+','+bT);
    }

    tipVal.setAttribute('x', tx); tipVal.setAttribute('y', bT + bh * 0.32);
    tipLbl.setAttribute('x', tx); tipLbl.setAttribute('y', bT + bh * 0.72);
    [tipBg, tipBdr, tipTip, tipVal, tipLbl].forEach(function(el) { el.setAttribute('opacity', '1'); });
  }

  function hideTip() {
    [tipBg, tipBdr, tipTip, tipVal, tipLbl].forEach(function(el) { el.setAttribute('opacity', '0'); });
  }

  /* §4 HOVER — area fills are large adjacent targets → container-level mouseleave */
  function svgMouseX(e) {
    var pt = svg.createSVGPoint();
    pt.x = e.clientX; pt.y = e.clientY;
    return pt.matrixTransform(svg.getScreenCTM().inverse()).x;
  }

  function nearestIdx(mx) {
    return Math.max(0, Math.min(n - 1, Math.round((mx - plotL) / step)));
  }

  /* HIT LAYER — built after all series, painted on top.
     Smallest series (highest index) appended last = topmost in SVG = wins hit-test.
     Each hit path uses the top-stroke geometry with a wide transparent stroke.
     This way hovering near any series' step edge is always reachable regardless
     of which fill area sits on top visually. */
  var hitLayer = document.createElementNS('http://www.w3.org/2000/svg', 'g');
  hitLayer.setAttribute('id', 'hit-layer');
  dataLayerEl.appendChild(hitLayer);

  /* append hit paths largest-first so smallest ends up on top */
  for (var hi = 0; hi < series.length; hi++) {
    (function(hi) {
      var hp = document.createElementNS('http://www.w3.org/2000/svg', 'path');
      hp.setAttribute('d', strokePath(series[hi].values));
      hp.setAttribute('fill', 'none');
      hp.setAttribute('stroke', 'transparent');
      hp.setAttribute('stroke-width', '20');
      hp.setAttribute('stroke-linejoin', 'round');
      hp.setAttribute('style', 'cursor:pointer');
      hp.setAttribute('data-si', hi);
      hitLayer.appendChild(hp);
    })(hi);
  }

  /* attach events to hit paths */
  var hitPaths = Array.prototype.slice.call(hitLayer.querySelectorAll('path'));
  /* reverse so iteration order matches series[] index */
  hitPaths.forEach(function(hp) {
    var si = parseInt(hp.getAttribute('data-si'));
    var s  = series[si];
    var sgEl = document.getElementById('sg' + si);

    function onMove(e) {
      if (!dataLayerEl.classList.contains('ready')) return;
      sgEls.forEach(function(el) { el.classList.remove('hovered'); });
      Array.prototype.forEach.call(dataLayerEl.querySelectorAll('.dot-g'), function(el) { el.classList.remove('hovered'); });
      dataLayerEl.classList.add('hovering');
      sgEl.classList.add('hovered');
      var idx   = nearestIdx(svgMouseX(e));
      var dotGs = sgEl.querySelectorAll('.dot-g');
      if (dotGs[idx]) dotGs[idx].classList.add('hovered');
      showTip(xAt(idx), yAt(s.values[idx]),
              '$' + s.values[idx] + 'k',
              s.name + ' \u00b7 ' + months[idx]);
    }
    hp.addEventListener('mouseenter', onMove);
    hp.addEventListener('mousemove',  onMove);
  });

  dataLayerEl.addEventListener('mouseleave', function() {
    sgEls.forEach(function(el) { el.classList.remove('hovered'); });
    Array.prototype.forEach.call(dataLayerEl.querySelectorAll('.dot-g'), function(el) { el.classList.remove('hovered'); });
    dataLayerEl.classList.remove('hovering');
    hideTip();
  });

  /* PRINT TOGGLE */
  document.getElementById('print-toggle').addEventListener('click', function() {
    var thumb = document.getElementById('pthumb'), lbl = document.getElementById('plabel');
    if (svg.classList.toggle('print')) { thumb.setAttribute('cx','52'); lbl.textContent='Screen'; }
    else                               { thumb.setAttribute('cx','16'); lbl.textContent='Print'; }
  });

  /* §2 DARK MODE */
  function setMode(wantDark) {
    if (wantDark === isDark) return;
    isDark = wantDark;
    var thumb = document.getElementById('tthumb');
    var lbl   = document.getElementById('tlabel');
    if (wantDark) {
      svg.classList.add('dark');
      if (thumb) thumb.setAttribute('cx', '52');
      if (lbl)   lbl.textContent = 'Light';
    } else {
      svg.classList.remove('dark');
      if (thumb) thumb.setAttribute('cx', '16');
      if (lbl)   lbl.textContent = 'Dark';
    }
  }

  document.getElementById('dark-toggle').addEventListener('click', function() { setMode(!isDark); });
  window.setMode = setMode;
  window.addEventListener('message', function(e) {
    if (e.data && e.data.type === 'setMode') setMode(e.data.dark);
  });
  setMode(window.location.href.indexOf('theme=dark') !== -1);
})();
